function decodeGoogleJWT(credential) {
  // The credential is a JWT: header.payload.signature (base64url).
  const payload = credential.split(".")[1];
  const base64 = payload.replace(/-/g, "+").replace(/_/g, "/");
  const padded = base64 + "===".slice((base64.length + 3) % 4);
  const json = decodeURIComponent(
    atob(padded)
      .split("")
      .map((c) => "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2))
      .join("")
  );
  return JSON.parse(json);
}

async function callClaude(userPrompt, systemPrompt) {
  const response = await fetch(CLAUDE_API_ENDPOINT, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1000,
      system: systemPrompt,
      messages: [{ role: "user", content: userPrompt }],
    }),
  });
  if (!response.ok) throw new Error("AI request failed (" + response.status + ")");
  const data = await response.json();
  const text = (data.content || [])
    .map((block) => (block.type === "text" ? block.text : ""))
    .filter(Boolean)
    .join("\n")
    .trim();
  if (!text) throw new Error("Empty AI response");
  return text;
}

async function getPracticeFeedback(question, answer, position) {
  const system =
    "You are acting as an experienced HR Officer, Interview Panel Member, and Written " +
    "Examination Reviewer for the Philippine civil service. You are evaluating a practice " +
    "answer from a candidate applying for a " + position + " position. " +
    "Respond with STRICT JSON ONLY, no markdown fences, no preamble, in this exact shape: " +
    '{"score": <integer 0-100>, "feedback": "<3-5 sentences>"}. ' +
    "The feedback must be a single flowing paragraph — do NOT break it into labeled categories " +
    "like Relevance, Grammar, Confidence, Organization, or Communication. Just one holistic, " +
    "encouraging, constructive paragraph that names a genuine strength, one concrete area to " +
    "improve, and one practical tip for next time. Be warm but honest, professional, human.";
  const user = "Question:\n" + question + "\n\nCandidate's answer:\n" + answer;
  const raw = await callClaude(user, system);
  const cleaned = raw.replace(/```json|```/g, "").trim();
  try {
    const parsed = JSON.parse(cleaned);
    return {
      score: Math.max(0, Math.min(100, Math.round(Number(parsed.score) || 0))),
      feedback: String(parsed.feedback || "").trim(),
    };
  } catch (e) {
    return { score: null, feedback: raw };
  }
}

async function getPersonalizedAnswer(question, position, pdsInfo, wesInfo) {
  const currentPosition = (pdsInfo && pdsInfo.currentPosition) || "";
  const system =
    "You help Philippine government " + position + " applicants prepare for written exams " +
    "and interviews. Using the candidate's own background below, write ONE natural, first-person, " +
    "conversational, professional answer (4-8 sentences) to the question. Sound like a real " +
    "applicant speaking, not a template. Do not invent specific employers, dates, or numbers " +
    "that are not implied by the background — if the background is thin, keep the answer more " +
    "general but still personal in tone. " +
    (currentPosition
      ? "The candidate currently works as \"" + currentPosition + "\" and is applying for " + position +
        ". Where it genuinely fits the question, draw a natural connection between their current " +
        "role and this target role — name a transferable skill or habit, without overstating unrelated " +
        "experience or claiming duties they haven't actually had."
      : "The candidate does not appear to be currently employed (e.g. a fresh graduate) — keep the " +
        "answer grounded in their education/eligibility rather than inventing work experience.") +
    " Return ONLY the answer text, nothing else.";
  const bg =
    "Applicant background (from Personal Data Sheet):\n" +
    "Name: " + ((pdsInfo && pdsInfo.name) || "(not provided)") + "\n" +
    "Current position: " + (currentPosition || "(none / fresh graduate)") + "\n" +
    "Education: " + ((pdsInfo && pdsInfo.education) || "(not provided)") + "\n" +
    "Eligibility: " + ((pdsInfo && pdsInfo.eligibility) || "(not provided)") + "\n" +
    "Experience summary (PDS): " + ((pdsInfo && pdsInfo.experienceSummary) || "(not provided)") +
    "\n\nFrom Work Experience Sheet:\n" +
    "Experience summary (WES): " + ((wesInfo && wesInfo.experienceSummary) || "(not provided)") + "\n" +
    "Key skills: " + ((wesInfo && wesInfo.keySkills) || "(not provided)");
  const user = bg + "\n\nQuestion:\n" + question;
  return await callClaude(user, system);
}

/* ---- File upload -> AI extraction (PDS / WES) ---- */
function readFileAsBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result).split(",")[1]);
    reader.onerror = () => reject(new Error("Could not read the file"));
    reader.readAsDataURL(file);
  });
}

async function callClaudeWithFile(fileBlock, instruction, systemPrompt) {
  const response = await fetch(CLAUDE_API_ENDPOINT, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1000,
      system: systemPrompt,
      messages: [{ role: "user", content: [fileBlock, { type: "text", text: instruction }] }],
    }),
  });
  if (!response.ok) throw new Error("AI request failed (" + response.status + ")");
  const data = await response.json();
  const text = (data.content || [])
    .map((block) => (block.type === "text" ? block.text : ""))
    .filter(Boolean)
    .join("\n")
    .trim();
  if (!text) throw new Error("Empty AI response");
  return text;
}

function fileToContentBlock(base64, mediaType) {
  if (mediaType === "application/pdf") {
    return { type: "document", source: { type: "base64", media_type: mediaType, data: base64 } };
  }
  return { type: "image", source: { type: "base64", media_type: mediaType || "image/png", data: base64 } };
}

async function analyzePDSFile(file) {
  const base64 = await readFileAsBase64(file);
  const block = fileToContentBlock(base64, file.type);
  const system =
    'You extract structured facts from a Philippine government Personal Data Sheet (CS Form 212). ' +
    'Respond with STRICT JSON ONLY, no markdown fences, no preamble, in exactly this shape: ' +
    '{"name":"","currentPosition":"","education":"","eligibility":"","experienceSummary":""}. ' +
    'currentPosition should be the most recent/present job title and employer if shown in the work ' +
    'experience section, or an empty string if the sheet shows no current employment (e.g. a fresh ' +
    'graduate). experienceSummary should be 2-3 sentences in plain language summarizing relevant work ' +
    "history. If a field truly isn't visible in the document, use an empty string rather than guessing.";
  const raw = await callClaudeWithFile(block, "Extract the requested fields from this Personal Data Sheet.", system);
  const cleaned = raw.replace(/```json|```/g, "").trim();
  return JSON.parse(cleaned);
}

async function analyzeWESFile(file) {
  const base64 = await readFileAsBase64(file);
  const block = fileToContentBlock(base64, file.type);
  const system =
    'You extract structured facts from a Philippine government Work Experience Sheet. ' +
    'Respond with STRICT JSON ONLY, no markdown fences, no preamble, in exactly this shape: ' +
    '{"experienceSummary":"","keySkills":""}. experienceSummary should be 2-4 sentences summarizing ' +
    "the candidate's actual duties and work history in plain language. keySkills should be a short " +
    "comma-separated list of concrete skills evidenced by the entries. If nothing is visible, use empty strings.";
  const raw = await callClaudeWithFile(block, "Extract the requested fields from this Work Experience Sheet.", system);
  const cleaned = raw.replace(/```json|```/g, "").trim();
  return JSON.parse(cleaned);
}

