function QACard({ q, a, tip }) {
  const [open, setOpen] = useState(false);
  return (
    <Card>
      <button className="qa-head" onClick={() => setOpen((o) => !o)}>
        <span className="qa-q">{q}</span>
        <ChevronDown size={16} style={{ transform: open ? "rotate(180deg)" : "none", transition: "transform .2s", flexShrink: 0 }} />
      </button>
      {open && (
        <div className="qa-body">
          <p>{a}</p>
          {tip && <div className="tip-note">{tip}</div>}
        </div>
      )}
    </Card>
  );
}

function PublicMCQPreview() {
  const [answers, setAnswers] = useState({});
  const choose = (qi, oi) => { if (answers[qi] === undefined) setAnswers((a) => ({ ...a, [qi]: oi })); };
  const score = Object.keys(answers).reduce((s, qi) => s + (answers[qi] === PUBLIC_MCQ[qi].correct ? 1 : 0), 0);
  return (
    <>
      <div className="quiz-score-pill">Score: {score} / {PUBLIC_MCQ.length}</div>
      {PUBLIC_MCQ.map((it, qi) => (
        <Card key={qi}>
          <div className="q-num">Question {qi + 1} of {PUBLIC_MCQ.length}</div>
          <p className="q-text">{it.q}</p>
          <div className="mcq-options">
            {it.opts.map((opt, oi) => {
              const revealed = answers[qi] !== undefined;
              const chosen = answers[qi] === oi;
              const isCorrect = oi === it.correct;
              let cls = "mcq-option";
              if (revealed && isCorrect) cls += " correct";
              else if (revealed && chosen && !isCorrect) cls += " wrong";
              return (
                <button key={oi} className={cls} onClick={() => choose(qi, oi)} disabled={revealed}>
                  {opt}
                  {revealed && isCorrect && <Check size={14} />}
                  {revealed && chosen && !isCorrect && <X size={14} />}
                </button>
              );
            })}
          </div>
          {answers[qi] !== undefined && <div className="mcq-explain"><strong>Why: </strong>{it.why}</div>}
        </Card>
      ))}
    </>
  );
}

function RankingCalculator({ role }) {
  const [vals, setVals] = useState(() => role.criteria.map(() => 0));
  useEffect(() => { setVals(role.criteria.map(() => 0)); }, [role]);
  const total = vals.reduce((a, b) => a + b, 0);
  let verdict = "Move the sliders to estimate your standing.";
  let verdictClass = "";
  if (total >= 80) { verdict = "Strong profile — you'd likely rank near the top."; verdictClass = "good"; }
  else if (total >= 60) { verdict = "Solid, competitive standing — a few more MOVs could push you higher."; verdictClass = "mid"; }
  else if (total > 0) { verdict = "Room to grow — focus on Experience, Performance, and Potential, they carry the most weight."; verdictClass = "warn"; }
  return (
    <Card accent>
      <SectionLabel>Try it yourself</SectionLabel>
      <p className="muted-line small">Slide to estimate your own score. This is a guide only — the actual HRMPSB rubric uses precise increments and MOVs.</p>
      {role.criteria.map((c, i) => (
        <div key={i} className="slider-row">
          <div className="slider-label"><span>{c.name}</span><span className="slider-val">{vals[i]} / {c.pts}</span></div>
          <input type="range" min={0} max={c.pts} value={vals[i]} onChange={(e) => { const v = [...vals]; v[i] = Number(e.target.value); setVals(v); }} />
        </div>
      ))}
      <div className="calc-total-row">
        <div>
          <div className="calc-total-num">{total}</div>
          <div className="muted-line small" style={{ marginBottom: 0 }}>estimated points / 100</div>
        </div>
        <ScoreRing score={total} />
      </div>
      {verdict && <div className={"calc-verdict " + verdictClass}>{verdict}</div>}
    </Card>
  );
}

