function Profile({ state, kraData, updateProfile, updateAuthName }) {
  const [name, setName] = useState(state.auth?.name || "");
  const [position, setPosition] = useState(state.profile.position);
  const [pdsInfo, setPdsInfo] = useState(state.profile.pdsInfo);
  const [wesInfo, setWesInfo] = useState(state.profile.wesInfo);
  const [saved, setSaved] = useState(false);

  const [pdsFileName, setPdsFileName] = useState("");
  const [wesFileName, setWesFileName] = useState("");
  const [analyzingPds, setAnalyzingPds] = useState(false);
  const [analyzingWes, setAnalyzingWes] = useState(false);
  const [uploadError, setUploadError] = useState("");

  const total = totalTopicCount(kraData || AO_KRA_DATA);
  const done = state.progress.completedTopics.length;

  const save = () => {
    updateAuthName(name);
    updateProfile({ position, pdsInfo, wesInfo });
    setSaved(true);
    setTimeout(() => setSaved(false), 1800);
  };

  const handlePdsUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setPdsFileName(file.name); setAnalyzingPds(true); setUploadError("");
    try {
      const info = await analyzePDSFile(file);
      setPdsInfo(info);
    } catch (err) {
      setUploadError("Couldn't read that PDS — try a clearer scan, or a PDF export instead of a photo.");
    } finally {
      setAnalyzingPds(false);
    }
  };

  const handleWesUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setWesFileName(file.name); setAnalyzingWes(true); setUploadError("");
    try {
      const info = await analyzeWESFile(file);
      setWesInfo(info);
    } catch (err) {
      setUploadError("Couldn't read that Work Experience Sheet — try a clearer scan or a PDF export.");
    } finally {
      setAnalyzingWes(false);
    }
  };

  const downloadHistory = () => {
    const blob = new Blob([JSON.stringify(state.practiceHistory, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = "rankup-practice-history.json";
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="screen">
      <ScreenHeader title="Profile" />
      <Card>
        <div className="avatar-row">
          {state.auth?.picture ? (
            <img src={state.auth.picture} alt="" className="avatar-circle avatar-photo" referrerPolicy="no-referrer" />
          ) : (
            <div className="avatar-circle">{(name || "?").charAt(0).toUpperCase()}</div>
          )}
          <div>
            <div className="profile-name">{name || "Your name"}</div>
            <div className="profile-email">{state.auth?.email}</div>
            {state.auth?.googleId && <div className="google-linked-tag"><GoogleG /> Google account</div>}
          </div>
        </div>
      </Card>

      <Card>
        <SectionLabel>Edit Profile</SectionLabel>
        <label className="field-label">Full Name</label>
        <input className="text-input" value={name} onChange={(e) => setName(e.target.value)} />
        <label className="field-label">Position you're applying for</label>
        <select className="text-input" value={position} onChange={(e) => setPosition(e.target.value)}>
          <option>AO II</option>
          <option>Administrative Aide (ADAS)</option>
        </select>
        <p className="muted-line small" style={{ marginTop: 8, marginBottom: 0 }}>
          This selection controls which Reviewer content, exam questions, and interview practice you see — AO topics for AO II, ADAS-specific topics for Administrative Aide.
        </p>
      </Card>

      <Card>
        <SectionLabel><Upload size={11} style={{ marginRight: 4, verticalAlign: -1 }} />Personal Data Sheet (PDS)</SectionLabel>
        <p className="muted-line small">Upload a PDF or a clear photo — the AI reads it once to detect your current job and background, so practice answers can connect it to the role you're applying for.</p>
        <label className="upload-btn">
          {analyzingPds ? <Loader2 size={14} className="spin" /> : <Upload size={14} />}
          {analyzingPds ? "Reading your PDS…" : (pdsFileName || "Choose PDS file (PDF or image)")}
          <input type="file" accept="application/pdf,image/*" onChange={handlePdsUpload} hidden />
        </label>
        {pdsInfo && (
          <div className="detected-box">
            <div className="detected-row"><span>Current position</span></div>
            <input className="text-input" value={pdsInfo.currentPosition || ""} placeholder="Not currently employed / fresh graduate"
              onChange={(e) => setPdsInfo({ ...pdsInfo, currentPosition: e.target.value })} />
            <div className="detected-row" style={{ marginTop: 8 }}><span>Education</span><strong>{pdsInfo.education || "—"}</strong></div>
            <div className="detected-row"><span>Eligibility</span><strong>{pdsInfo.eligibility || "—"}</strong></div>
            {pdsInfo.experienceSummary && <p className="muted-line small" style={{ marginTop: 8 }}>{pdsInfo.experienceSummary}</p>}
          </div>
        )}
      </Card>

      <Card>
        <SectionLabel><Upload size={11} style={{ marginRight: 4, verticalAlign: -1 }} />Work Experience Sheet (WES)</SectionLabel>
        <label className="upload-btn">
          {analyzingWes ? <Loader2 size={14} className="spin" /> : <Upload size={14} />}
          {analyzingWes ? "Reading your WES…" : (wesFileName || "Choose WES file (PDF or image)")}
          <input type="file" accept="application/pdf,image/*" onChange={handleWesUpload} hidden />
        </label>
        {wesInfo && (
          <div className="detected-box">
            {wesInfo.experienceSummary && <p className="muted-line small" style={{ marginTop: 0 }}>{wesInfo.experienceSummary}</p>}
            {wesInfo.keySkills && <div className="detected-row"><span>Key skills</span><strong>{wesInfo.keySkills}</strong></div>}
          </div>
        )}
      </Card>

      {uploadError && <div className="error-line"><AlertCircle size={13} /> {uploadError}</div>}

      <button className="primary-btn full" onClick={save}>
        {saved ? <Check size={15} /> : <RefreshCw size={15} />} {saved ? "Saved" : "Save changes"}
      </button>

      <div className="dash-section-title">Progress</div>
      <div className="stat-grid">
        <div className="stat-card"><CircleCheck size={16} /><div className="stat-num">{done}/{total}</div><div className="stat-label">Completed Topics</div></div>
        <div className="stat-card"><FileText size={16} /><div className="stat-num">{state.practiceHistory.length}</div><div className="stat-label">Practice Answers</div></div>
      </div>

      <button className="ghost-btn full" onClick={downloadHistory} disabled={state.practiceHistory.length === 0}>
        <Download size={15} /> Download Practice History
      </button>
    </div>
  );
}

/* ============================================================
   SETTINGS
   ============================================================ */
function Settings({
  theme, setTheme, onLogout, authEmail,
  isGoogleLinked, sharePresence, onSetSharePresence,
  onChangePassword, onSetLocalPassword, onUnlinkGoogle, hasLocalPassword,
}) {
  const [pwOpen, setPwOpen] = useState(false);
  const [curPw, setCurPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [pwMsg, setPwMsg] = useState(null); // { ok, message }
  const [pwBusy, setPwBusy] = useState(false);

  const [googleOpen, setGoogleOpen] = useState(false);
  const [confirmUnlink, setConfirmUnlink] = useState(false);

  const closePwForm = () => { setPwOpen(false); setCurPw(""); setNewPw(""); setConfirmPw(""); setPwMsg(null); };

  const submitPw = async () => {
    if (newPw !== confirmPw) { setPwMsg({ ok: false, message: "New password and confirmation don't match." }); return; }
    setPwBusy(true);
    const result = hasLocalPassword
      ? await onChangePassword(curPw, newPw)
      : await onSetLocalPassword(newPw);
    setPwBusy(false);
    setPwMsg(result);
    if (result.ok) { setCurPw(""); setNewPw(""); setConfirmPw(""); }
  };

  return (
    <div className="screen">
      <ScreenHeader title="Settings" />
      <Card>
        <SectionLabel>Appearance</SectionLabel>
        <div className="settings-row">
          <span>Theme</span>
          <div className="segmented">
            <button className={theme === "dark" ? "seg active" : "seg"} onClick={() => setTheme("dark")}><Moon size={13} /> Dark</button>
            <button className={theme === "light" ? "seg active" : "seg"} onClick={() => setTheme("light")}><Sun size={13} /> Light</button>
          </div>
        </div>
      </Card>

      <Card>
        <SectionLabel>Account</SectionLabel>
        <div className="settings-row"><span>Signed in as</span><span className="muted-line small">{authEmail}</span></div>

        <div className="settings-row">
          <span>{hasLocalPassword ? "Change Password" : "Set a Password"}</span>
          <button
            className="link-btn"
            onClick={() => { setPwOpen((o) => !o); setPwMsg(null); setGoogleOpen(false); }}
          >
            {pwOpen ? "Close" : (hasLocalPassword ? "Change" : "Set up")}
          </button>
        </div>
        {pwOpen && (
          <div className="inline-form">
            {isGoogleLinked && !hasLocalPassword && (
              <p className="muted-line small">You signed in with Google, so there's no password yet. Set one here as a backup way to sign in on this device.</p>
            )}
            {hasLocalPassword && (
              <label className="auth-field">Current password
                <input type="password" value={curPw} onChange={(e) => setCurPw(e.target.value)} />
              </label>
            )}
            <label className="auth-field">New password
              <input type="password" value={newPw} onChange={(e) => setNewPw(e.target.value)} />
            </label>
            <label className="auth-field">Confirm new password
              <input type="password" value={confirmPw} onChange={(e) => setConfirmPw(e.target.value)} />
            </label>
            {pwMsg && (
              <div className={pwMsg.ok ? "success-line" : "error-line"}>
                {pwMsg.ok ? <CircleCheck size={13} /> : <AlertCircle size={13} />} {pwMsg.message}
              </div>
            )}
            <div className="practice-actions">
              <button className="primary-btn" onClick={submitPw} disabled={pwBusy || !newPw || !confirmPw || (hasLocalPassword && !curPw)}>
                {pwBusy ? <Loader2 size={14} className="spin" /> : <Check size={14} />} Save
              </button>
              <button className="ghost-btn" onClick={closePwForm}>Cancel</button>
            </div>
            <p className="muted-line small" style={{ marginTop: 6 }}>
              This password is stored only on this device (there's no server), so it won't follow you to a new phone or browser.
            </p>
          </div>
        )}

        <div className="settings-row">
          <span>Google Account Management</span>
          <button className="link-btn" onClick={() => { setGoogleOpen((o) => !o); setPwOpen(false); }}>
            {googleOpen ? "Close" : "Manage"}
          </button>
        </div>
        {googleOpen && (
          <div className="inline-form">
            {isGoogleLinked ? (
              <>
                <p className="muted-line small">Your account is linked to Google (<strong>{authEmail}</strong>). Sign-in uses Google, not a password stored here.</p>
                {!confirmUnlink ? (
                  <button className="ghost-btn full" onClick={() => setConfirmUnlink(true)}>Unlink Google account</button>
                ) : (
                  <>
                    <p className="muted-line small">This turns your account into a device-only email/password account. You'll be asked to set a password next.</p>
                    <div className="practice-actions">
                      <button
                        className="danger-btn"
                        onClick={() => { onUnlinkGoogle(); setConfirmUnlink(false); setGoogleOpen(false); setPwOpen(true); setPwMsg(null); }}
                      >
                        Yes, unlink
                      </button>
                      <button className="ghost-btn" onClick={() => setConfirmUnlink(false)}>Cancel</button>
                    </div>
                  </>
                )}
              </>
            ) : (
              <p className="muted-line small">This account isn't linked to Google yet. Sign out, then choose "Continue with Google" on the sign-in screen using the same email to link it.</p>
            )}
          </div>
        )}
      </Card>

      <Card>
        <SectionLabel>Preferences</SectionLabel>
        <div className="settings-row">
          <span>Share "Online Now" presence</span>
          <button className={"toggle" + (sharePresence ? " on" : "")} onClick={() => onSetSharePresence(!sharePresence)}><span className="toggle-knob" /></button>
        </div>
        <p className="muted-line small" style={{ marginTop: -6 }}>
          When on, a random session id (no name or email) is briefly shared so other reviewers can see how many people are studying right now. Turn this off to browse without appearing in that count — nothing else about your account changes.
        </p>
      </Card>

      <button className="danger-btn full" onClick={onLogout}><LogOut size={15} /> Log out</button>
    </div>
  );
}

/* ============================================================
   AUTH SCREENS
   ============================================================ */
function AuthScreen({ onAuth, onPreview, localAccounts, onRegisterAccount }) {
  const [mode, setMode] = useState("signin"); // signin | signup
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);
  const [googleReady, setGoogleReady] = useState(false);
  const googleBtnRef = useRef(null);

  const handleGoogleCredential = useCallback((response) => {
    try {
      const profile = decodeGoogleJWT(response.credential);
      onAuth({
        name: profile.name || profile.email.split("@")[0],
        email: profile.email,
        picture: profile.picture || null,
        googleId: profile.sub,
      });
    } catch (e) {
      setError("Couldn't read your Google account. Please try again.");
    }
  }, [onAuth]);

  useEffect(() => {
    if (!GOOGLE_SIGNIN_CONFIGURED) return;
    let cancelled = false;

    const initGoogle = () => {
      if (cancelled || !window.google || !googleBtnRef.current) return;
      window.google.accounts.id.initialize({
        client_id: GOOGLE_CLIENT_ID,
        callback: handleGoogleCredential,
      });
      window.google.accounts.id.renderButton(googleBtnRef.current, {
        theme: "outline", size: "large", width: 320, text: "continue_with",
      });
      setGoogleReady(true);
    };

    if (window.google && window.google.accounts) {
      initGoogle();
    } else {
      const existing = document.getElementById("google-identity-script");
      if (!existing) {
        const script = document.createElement("script");
        script.src = "https://accounts.google.com/gsi/client";
        script.async = true;
        script.defer = true;
        script.id = "google-identity-script";
        script.onload = initGoogle;
        document.head.appendChild(script);
      } else {
        existing.addEventListener("load", initGoogle);
      }
    }
    return () => { cancelled = true; };
  }, [handleGoogleCredential]);

  const submit = async (e) => {
    e.preventDefault();
    if (mode === "signup" && !name.trim()) return setError("Please enter your full name.");
    if (!email.trim() || !email.includes("@")) return setError("Please enter a valid email address.");
    if (password.length < 4) return setError("Password must be at least 4 characters.");
    const key = email.trim().toLowerCase();
    setError(""); setBusy(true);
    try {
      const hash = await hashPassword(password);
      if (mode === "signup") {
        if (localAccounts[key]) { setError("An account already exists for that email — sign in instead."); return; }
        onRegisterAccount(key, { name: name.trim(), passwordHash: hash });
        onAuth({ name: name.trim(), email: email.trim() });
      } else {
        const existing = localAccounts[key];
        if (!existing) { setError("No account found for that email on this device — sign up first, or use Google."); return; }
        if (existing.passwordHash !== hash) { setError("Incorrect password."); return; }
        onAuth({ name: existing.name, email: email.trim() });
      }
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="screen auth-screen">
      <div className="auth-card">
        <div className="auth-brand">
          <div className="auth-mark"><img src={LOGO_DATA_URI} alt="RankUp logo" /></div>
          <div className="auth-t1">RankUp</div>
          <div className="auth-t2">AO &amp; ADAS Reviewer</div>
        </div>

        <div className="auth-tabs">
          <button className={mode === "signin" ? "auth-tab active" : "auth-tab"} onClick={() => setMode("signin")}>Sign In</button>
          <button className={mode === "signup" ? "auth-tab active" : "auth-tab"} onClick={() => setMode("signup")}>Sign Up</button>
        </div>

        <div className="auth-google-slot">
          {GOOGLE_SIGNIN_CONFIGURED ? (
            <>
              <div ref={googleBtnRef} className="google-btn-slot" />
              {!googleReady && (
                <button className="google-btn" disabled>
                  <Loader2 size={14} className="spin" /> Loading Google Sign-In…
                </button>
              )}
            </>
          ) : (
            <button className="google-btn" disabled title="Add your Google Client ID in the code to enable this">
              <GoogleG /> Continue with Google
            </button>
          )}
        </div>

        <div className="auth-divider"><span>or use your email</span></div>

        <form onSubmit={submit} className="auth-form">
          {mode === "signup" && (
            <label className="auth-field">Full name
              <input placeholder="Juan Dela Cruz" value={name} onChange={(e) => setName(e.target.value)} />
            </label>
          )}
          <label className="auth-field">Email address
            <input type="email" placeholder="you@example.com" value={email} onChange={(e) => setEmail(e.target.value)} />
          </label>
          <label className="auth-field">Password
            <div className="input-with-icon">
              <input type={showPw ? "text" : "password"} placeholder="Your password" value={password} onChange={(e) => setPassword(e.target.value)} />
              <button type="button" className="pw-toggle" onClick={() => setShowPw((s) => !s)}>{showPw ? <EyeOff size={15} /> : <Eye size={15} />}</button>
            </div>
          </label>
          {error && <div className="error-line"><AlertCircle size={13} /> {error}</div>}
          <button type="submit" className="primary-btn full" disabled={busy}>
            {busy ? <Loader2 size={14} className="spin" /> : null}
            {mode === "signin" ? "Sign In" : "Create Account"}
          </button>
        </form>

        <div className="auth-switch">
          {mode === "signin" ? (
            <>New here? <button type="button" className="link-btn" onClick={() => setMode("signup")}>Create an account</button></>
          ) : (
            <>Already have an account? <button type="button" className="link-btn" onClick={() => setMode("signin")}>Sign in</button></>
          )}
        </div>

        <p className="auth-note">
          {GOOGLE_SIGNIN_CONFIGURED
            ? "Google Sign-In is live. Email/password below is stored on this device only (no server), so use Google for a real account."
            : "Google Sign-In needs a one-time setup — add your own Client ID at the top of the code (see the chat for the 3-step guide). Email/password below is stored on this device only, not a real server account."}
        </p>
      </div>

      <button className="link-btn preview-link" onClick={onPreview}>Preview the reviewer first, no account needed →</button>
    </div>
  );
}

