/* ============================================================
   NAV / SHELL
   ============================================================ */
const NAV_ITEMS = [
  { id: "dashboard", label: "Dashboard", icon: Home },
  { id: "reviewer", label: "Reviewer", icon: BookOpen },
  { id: "interview", label: "Interview", icon: Mic },
  { id: "profile", label: "Profile", icon: UserIcon },
  { id: "settings", label: "Settings", icon: SettingsIcon },
];

export default function App() {
  const [loaded, setLoaded] = useState(false);
  const [showSplash, setShowSplash] = useState(true);
  const [splashHiding, setSplashHiding] = useState(false);
  const [state, setState] = useState(defaultState);
  const [theme, setTheme] = useState("dark");
  const [tab, setTab] = useState("dashboard");
  const [kraId, setKraId] = useState(null);
  const [topicId, setTopicId] = useState(null);
  const [showOverview, setShowOverview] = useState(false);
  const [reviewerSubtab, setReviewerSubtab] = useState("kra");
  const [onlineCount, setOnlineCount] = useState(1);
  const sessionIdRef = useRef(null);
  const saveTimer = useRef(null);

  useEffect(() => {
    (async () => {
      const s = await loadState();
      setState(s);
      setLoaded(true);
    })();
  }, []);

  // Keep the branded splash on screen long enough to actually be seen (state
  // usually loads almost instantly), then fade it out before revealing the
  // sign-in / app screens underneath.
  useEffect(() => {
    if (!loaded) return;
    const minTimer = setTimeout(() => {
      setSplashHiding(true);
      setTimeout(() => setShowSplash(false), 600);
    }, 1300);
    return () => clearTimeout(minTimer);
  }, [loaded]);

  useEffect(() => {
    if (!loaded) return;
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => saveState(state), 400);
    return () => clearTimeout(saveTimer.current);
  }, [state, loaded]);

  // Live "online now" presence — a lightweight shared heartbeat, no personal
  // info stored, just a random session id + timestamp so we can count how
  // many sessions have checked in within the last 90 seconds.
  useEffect(() => {
    if (!loaded || !state.auth) return;
    if (state.settings?.sharePresence === false) { setOnlineCount(1); return; }
    if (!sessionIdRef.current) {
      sessionIdRef.current = "sess-" + Math.random().toString(36).slice(2) + Date.now().toString(36);
    }
    let cancelled = false;

    const heartbeat = async () => {
      try {
        await storage.set("presence:" + sessionIdRef.current, JSON.stringify({ ts: Date.now() }), true);
        const list = await storage.list("presence:", true);
        if (!list || !list.keys || cancelled) return;
        const keys = list.keys.slice(0, 60); // cap fan-out for a demo-scale check
        const now = Date.now();
        const results = await Promise.all(
          keys.map(async (k) => {
            try {
              const r = await storage.get(k, true);
              if (!r) return null;
              const v = JSON.parse(r.value);
              return v.ts;
            } catch (e) {
              return null;
            }
          })
        );
        const active = results.filter((ts) => ts && now - ts < 90000).length;
        if (!cancelled) setOnlineCount(Math.max(1, active));
      } catch (e) {
        /* presence is a nice-to-have, fail silently */
      }
    };

    heartbeat();
    const interval = setInterval(heartbeat, 25000);
    return () => { cancelled = true; clearInterval(interval); };
  }, [loaded, state.auth, state.settings?.sharePresence]);

  const pushActivity = useCallback((label, detail) => {
    setState((s) => ({
      ...s,
      recentActivity: [{ id: Date.now() + Math.random(), label, detail, date: new Date().toISOString() }, ...s.recentActivity].slice(0, 20),
    }));
  }, []);

  const handleAuth = (auth) => {
    setState((s) => ({ ...s, auth }));
  };

  const registerAccount = (emailKey, record) => {
    setState((s) => ({ ...s, localAccounts: { ...s.localAccounts, [emailKey]: record } }));
  };

  // Change Password (Settings): only meaningful for device-local email/password
  // accounts. Verifies the current password against the stored hash, then
  // saves a new hash. Returns { ok, message } so the Settings UI can show a
  // clear result instead of silently doing nothing.
  const changePassword = async (currentPw, newPw) => {
    const key = (state.auth?.email || "").toLowerCase();
    const existing = state.localAccounts?.[key];
    if (!existing) return { ok: false, message: "No local password is set for this account yet." };
    if (newPw.length < 4) return { ok: false, message: "New password must be at least 4 characters." };
    const currentHash = await hashPassword(currentPw);
    if (currentHash !== existing.passwordHash) return { ok: false, message: "Current password is incorrect." };
    const newHash = await hashPassword(newPw);
    setState((s) => ({ ...s, localAccounts: { ...s.localAccounts, [key]: { ...existing, passwordHash: newHash } } }));
    return { ok: true, message: "Password updated." };
  };

  // Set a first-time local password — used right after unlinking a Google
  // account, since Google-linked accounts never had a local password.
  const setLocalPassword = async (newPw) => {
    const key = (state.auth?.email || "").toLowerCase();
    if (newPw.length < 4) return { ok: false, message: "Password must be at least 4 characters." };
    const newHash = await hashPassword(newPw);
    setState((s) => ({
      ...s,
      localAccounts: { ...s.localAccounts, [key]: { name: s.auth?.name || "", passwordHash: newHash } },
    }));
    return { ok: true, message: "Password set." };
  };

  const unlinkGoogleAccount = () => {
    setState((s) => (s.auth ? { ...s, auth: { name: s.auth.name, email: s.auth.email } } : s));
  };

  const setSharePresence = (on) => {
    setState((s) => ({ ...s, settings: { ...s.settings, sharePresence: on } }));
  };

  const handleLogout = () => {
    setState((s) => ({ ...s, auth: null }));
    setTab("dashboard");
  };

  const updateProfile = (patch) => {
    setState((s) => ({ ...s, profile: { ...s.profile, ...patch } }));
  };
  const updateAuthName = (name) => {
    setState((s) => ({ ...s, auth: s.auth ? { ...s.auth, name } : s.auth }));
  };

  const markComplete = (topicIdToMark, topicTitle) => {
    setState((s) => {
      if (s.progress.completedTopics.includes(topicIdToMark)) return s;
      return { ...s, progress: { ...s.progress, completedTopics: [...s.progress.completedTopics, topicIdToMark] } };
    });
    pushActivity("Topic reviewed", topicTitle);
  };

  const logMCQScore = (topicIdKey, score, total) => {
    setState((s) => ({
      ...s,
      progress: {
        ...s.progress,
        mcqScores: {
          ...s.progress.mcqScores,
          [topicIdKey]: [...(s.progress.mcqScores[topicIdKey] || []), { score, total, date: new Date().toISOString() }],
        },
      },
    }));
    pushActivity("Quiz completed", `${score}/${total} on ${topicIdKey.replace(/-/g, " ")}`);
  };

  const logHistory = ({ question, answer, score, feedback, kind }) => {
    setState((s) => ({
      ...s,
      progress: {
        ...s.progress,
        interviewCount: kind === "interview" ? s.progress.interviewCount + 1 : s.progress.interviewCount,
        essayCount: kind === "essay" ? s.progress.essayCount + 1 : s.progress.essayCount,
      },
      practiceHistory: [{ id: Date.now() + Math.random(), question, answer, score, feedback, kind, date: new Date().toISOString() }, ...s.practiceHistory].slice(0, 100),
    }));
    pushActivity(kind === "essay" ? "Essay scored" : "Interview answer scored", score !== null ? `Score: ${score}/100` : "Reviewed");
  };

  const findFirstIncomplete = () => {
    const kd = kraDataForPosition(state.profile.position);
    for (const k of kd) {
      for (const t of k.topics) {
        if (t.built && !state.progress.completedTopics.includes(t.id)) {
          setTab("reviewer"); setKraId(k.id); setTopicId(t.id);
          return;
        }
      }
    }
    setTab("reviewer"); setKraId(kd[0].id); setTopicId(null);
  };

  const goTab = (id) => { setTab(id); setKraId(null); setTopicId(null); setReviewerSubtab("kra"); };

  // Back button / swipe-back fix: with no History API usage at all, the
  // device/browser Back action had nowhere to go inside the app, so it left
  // the page entirely and landed users back on the sign-in screen on
  // re-entry. This tracks "where the user is" as a history entry so Back
  // steps up one in-app screen at a time (topic -> KRA list -> Reviewer tab
  // -> Dashboard) instead of exiting the app.
  const navGuard = useRef(false);      // true while applying a Back/Forward-driven update
  const navInitialized = useRef(false); // true once the first history entry has been recorded
  const navSnapshot = state.auth
    ? { authed: true, tab, kraId, topicId, reviewerSubtab }
    : { authed: false, showOverview };

  useEffect(() => {
    if (!loaded || showSplash) return;
    if (navGuard.current) { navGuard.current = false; return; }
    if (!navInitialized.current) {
      navInitialized.current = true;
      window.history.replaceState(navSnapshot, "");
      return;
    }
    window.history.pushState(navSnapshot, "");
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loaded, showSplash, tab, kraId, topicId, reviewerSubtab, showOverview, !!state.auth]);

  useEffect(() => {
    const onPopState = (e) => {
      const nav = e.state;
      if (!nav) return; // no in-app entry recorded here — let the browser do its normal thing
      navGuard.current = true;
      if (nav.authed) {
        setShowOverview(false);
        setTab(nav.tab || "dashboard");
        setKraId(nav.kraId ?? null);
        setTopicId(nav.topicId ?? null);
        setReviewerSubtab(nav.reviewerSubtab || "kra");
      } else {
        setShowOverview(!!nav.showOverview);
      }
    };
    window.addEventListener("popstate", onPopState);
    return () => window.removeEventListener("popstate", onPopState);
  }, []);

  if (showSplash) {
    return (
      <div className="app-wrap" data-theme={theme}>
        <RankUpStyles />
        <div className={"app-screen splash-screen" + (splashHiding ? " splash-hide" : "")}>
          <div className="splash-logo-wrap">
            <img className="splash-logo" src={LOGO_DATA_URI} alt="RankUp logo" />
            <div className="splash-shine" />
          </div>
          <div className="splash-title">RankUp</div>
          <div className="splash-sub">AO &amp; ADAS Reviewer</div>
          <div className="splash-loader"><div className="splash-loader-bar" /></div>
        </div>
      </div>
    );
  }

  const kraData = kraDataForPosition(state.profile.position);

  return (
    <div className="app-wrap" data-theme={theme}>
      <RankUpStyles />
      <div className="app-screen">
        {!state.auth ? (
          showOverview ? (
            <>
              <div className="app-body">
                <PublicOverview onSignIn={() => setShowOverview(false)} />
              </div>
            </>
          ) : (
            <AuthScreen
              onAuth={handleAuth}
              onPreview={() => setShowOverview(true)}
              localAccounts={state.localAccounts || {}}
              onRegisterAccount={registerAccount}
            />
          )
        ) : (
          <>
            <div className="app-body">
              {tab === "dashboard" && (
                <Dashboard
                  state={state}
                  kraData={kraData}
                  onlineCount={onlineCount}
                  goReviewer={() => goTab("reviewer")}
                  goInterview={() => goTab("interview")}
                  goOverview={() => { setTab("overview"); setKraId(null); setTopicId(null); }}
                  findFirstIncomplete={findFirstIncomplete}
                />
              )}

              {tab === "overview" && (
                <PublicOverview mode="member" onSignIn={() => goTab("dashboard")} />
              )}

              {tab === "reviewer" && (
                <ReviewerScreen
                  reviewerSubtab={reviewerSubtab}
                  setReviewerSubtab={setReviewerSubtab}
                  kraData={kraData}
                  position={state.profile.position}
                  kraId={kraId}
                  setKraId={setKraId}
                  topicId={topicId}
                  setTopicId={setTopicId}
                  completedTopics={state.progress.completedTopics}
                  markComplete={markComplete}
                  logHistory={logHistory}
                  logMCQScore={logMCQScore}
                  pdsInfo={state.profile.pdsInfo}
                  wesInfo={state.profile.wesInfo}
                />
              )}

              {tab === "interview" && (
                <InterviewPractice position={state.profile.position} pdsInfo={state.profile.pdsInfo} wesInfo={state.profile.wesInfo} logHistory={logHistory} />
              )}

              {tab === "profile" && (
                <Profile state={state} kraData={kraData} updateProfile={updateProfile} updateAuthName={updateAuthName} />
              )}

              {tab === "settings" && (
                <Settings
                  theme={theme}
                  setTheme={setTheme}
                  onLogout={handleLogout}
                  authEmail={state.auth.email}
                  isGoogleLinked={!!state.auth.googleId}
                  sharePresence={state.settings?.sharePresence !== false}
                  onSetSharePresence={setSharePresence}
                  onChangePassword={changePassword}
                  onSetLocalPassword={setLocalPassword}
                  onUnlinkGoogle={unlinkGoogleAccount}
                  hasLocalPassword={!!state.localAccounts?.[(state.auth.email || "").toLowerCase()]}
                />
              )}
            </div>

            <div className="bottom-nav">
              {NAV_ITEMS.map((item) => {
                const Icon = item.icon;
                const active = tab === item.id;
                return (
                  <button key={item.id} className={"nav-btn" + (active ? " active" : "")} onClick={() => goTab(item.id)}>
                    <Icon size={19} />
                    <span>{item.label}</span>
                  </button>
                );
              })}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

